import sys

def solve():
    n, s, r = map(int, sys.stdin.readline().split())
    a = list(map(int, sys.stdin.readline().split()))
    a.insert(0, 0)  # for convenience
    ans = 0
    for i in range(1, n + 1):
        l, r = i, i
        while l > 1 and a[l - 1] >= a[l] - r:
            l -= 1
        while r < n and a[r + 1] <= a[r] + r:
            r += 1
        sum_ = a[r] - a[l - 1]
        if sum_ <= s:
            ans += r - l + 1
    print(ans)

if __name__ == '__main__':
    solve()
