def count_calm_blocks(n, s, r, a):
    prefix_sum = [0] * (n + 1)
    for i in range(n):
        prefix_sum[i + 1] = prefix_sum[i] + a[i]

    calm_blocks = 0
    for i in range(n):
        for j in range(i, n):
            if prefix_sum[j + 1] - prefix_sum[i] <= s and max(a[j], a[i]) - min(a[j], a[i]) <= r:
                calm_blocks += 1

    return calm_blocks

